    has items: list = [];

    def add(it: LineItem) -> None {
        self.items.append(it);
    }

    def total -> float {
        raw = sum([it.subtotal() for it in self.items]);
        return round(raw * 0.9 if raw >= 100.0 else raw, 2);
    }
}

