obj BBox {
    has min_x: int = 0;
    has min_y: int = 0;
    has max_x: int = 0;
    has max_y: int = 0;

    def expand(p: list) -> None {
        self.min_x = min(self.min_x, p[0]);
        self.max_x = max(self.max_x, p[0]);
        self.min_y = min(self.min_y, p[1]);
        self.max_y = max(self.max_y, p[1]);
    }

    def dims -> list {
        return [self.max_x - self.min_x, self.max_y - self.min_y];
    }
}

def bounding_box(points: list) -> list {
    box = BBox(
        min_x=points[0][0], max_x=points[0][0],
        min_y=points[0][1], max_y=points[0][1]
    );
    for p in points[1:] {
        box.expand(p);
    }
    return box.dims();
}

with entry { print(bounding_box([[1, 2], [4, 6], [-2, 3]])); }

obj RunningStats {
    has n: int = 0;
    has mean: float = 0.0;
    has m2: float = 0.0;

    def add(x: float) -> None {
        self.n += 1;
        delta = x - self.mean;
        self.mean += delta / self.n;
        self.m2 += delta * (x - self.mean);
    }

    def variance -> float {
        return self.m2 / self.n if self.n else 0.0;
    }

    def snapshot -> list {
        return [self.n, round(self.mean, 3), round(self.variance(), 3)];
    }
}

def running_stats(values: list) -> list {
    rs = RunningStats();
    for x in values {
        rs.add(x);
    }
    return rs.snapshot();
}

with entry { print(running_stats([2.0, 4.0, 4.0, 4.0, 5.0, 5.0, 7.0, 9.0])); }

