obj Account {
    has balance: int = 0;
    has rejected: int = 0;
    has history: list = [];

    def apply(op: dict) -> None {
        match op["kind"] {
            case "dep":
                self.balance += op["amt"];
                self.history.append(op["amt"]);
            case "wd":
                if op["amt"] > self.balance {
                    self.rejected += 1;
                } else {
                    self.balance -= op["amt"];
                    self.history.append(-op["amt"]);
                }
        }
    }

    def summary -> list {
        return [self.balance, self.rejected, len(self.history)];
    }
}

def process_ledger(ops: list) -> list {
    acct = Account();
    for op in ops {
        acct.apply(op);
    }
    return acct.summary();
}

with entry { print(process_ledger([{'kind': 'dep', 'amt': 100}, {'kind': 'wd', 'amt': 30}, {'kind': 'wd', 'amt': 200}])); }

obj Poly {
    has coeffs: list = [];

    def value_at(x: int) -> int {
        total = 0;
        p = 1;
        for c in self.coeffs {
            total += c * p;
            p *= x;
        }
        return total;
    }

    def derive -> Poly {
        return Poly(coeffs=[i * self.coeffs[i] for i in range(1, len(self.coeffs))]);
    }
}

def poly_at(spec: dict) -> list {
    p = Poly(coeffs=spec["coeffs"]);
    x = spec["x"];
    return [p.value_at(x), p.derive().value_at(x)];
}

with entry { print(poly_at({'coeffs': [1, 0, 2], 'x': 3})); }
